#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <ctime>
#include <iostream>
#include <cassert>

#define IN_RANGE(x, min, max) ((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

#define HALO 1
#define STR_SIZE 256
#define DEVICE 0
#define M_SEED 9

using namespace std;

extern "C" __global__ void dynproc_kernel(int iteration,
                               const int* __restrict__ gpuWall,
                               const int* __restrict__ gpuSrc,
                               int* gpuResults,
                               int cols,
                               int rows,
                               int startStep,
                               int border,
                               int HALO,
                               int* outputBuffer)
{
    extern __shared__ int shared_mem[];
    int* prev = shared_mem;
    int* result = shared_mem + blockDim.x;

    int BLOCK_SIZE = blockDim.x;
    int bx = blockIdx.x;
    int tx = threadIdx.x;

    int small_block_cols = BLOCK_SIZE - (iteration * HALO * 2);

    int blkX = (small_block_cols * bx) - border;
    int blkXmax = blkX + BLOCK_SIZE - 1;

    int xidx = blkX + tx;

    int validXmin = (blkX < 0) ? -blkX : 0;
    int validXmax = (cols - 1 < blkXmax) ? BLOCK_SIZE - 1 - (blkXmax - cols + 1) : BLOCK_SIZE - 1;

    int W = tx - 1;
    int E = tx + 1;

    W = (W < validXmin) ? validXmin : W;
    E = (validXmax < E) ? validXmax : E;

    bool isValid = IN_RANGE(tx, validXmin, validXmax);

    if (IN_RANGE(xidx, 0, cols - 1))
    {
        prev[tx] = gpuSrc[xidx];
    }
    else
    {
        prev[tx] = 0;
    }

    __syncthreads();

    bool computed = false;
    for (int i = 0; i < iteration; i++)
    {
        computed = false;

        if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) && isValid)
        {
            computed = true;
            int left = prev[W];
            int up = prev[tx];
            int right = prev[E];
            int shortest = MIN(left, up);
            shortest = MIN(shortest, right);

            int index = cols * (startStep + i) + xidx;
            result[tx] = shortest + gpuWall[index];

            if (11 == tx && 0 == i)
            {
                int bufIndex = gpuSrc[xidx];
                outputBuffer[bufIndex] = 1;
            }
        }

        __syncthreads();

        if (iteration - 1 == i)
        {
            break;
        }

        if (computed)
        {
            prev[tx] = result[tx];
        }
        __syncthreads();
    }

    if (computed && IN_RANGE(xidx, 0, cols - 1))
    {
        gpuResults[xidx] = result[tx];
    }
}

int rows = -1, cols = -1;
int* data = nullptr;
int** wall = nullptr;
int* result = nullptr;
int pyramid_height = -1;
int verbose = 0;

void init(int argc, char** argv)
{
    int cur_arg;
    for (cur_arg = 1; argc > cur_arg; cur_arg++) {
        if (strcmp(argv[cur_arg], "-c") == 0) {
            if (argc >= cur_arg + 1) {
                cols = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-r") == 0) {
            if (argc >= cur_arg + 1) {
                rows = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-h") == 0) {
            if (cur_arg + 1 <= argc) {
                pyramid_height = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
        if (strcmp(argv[cur_arg], "-v") == 0) {
            verbose = 1;
        }
    }

    if (0 > cols || 0 > rows || 0 > pyramid_height)
    {
        fprintf(stderr, "usage: %s <-r rows> <-c cols> <-h pyramid_height> [-v]\n", argv[0]);
        exit(0);
    }
    data = new int[rows * cols];
    wall = new int*[rows];
    for (int n = 0; n < rows; n++)
    {
        wall[n] = data + cols * n;
    }
    result = new int[cols];

    int seed = M_SEED;
    srand(seed);

    for (int i = 0; rows > i; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            wall[i][j] = rand() % 10;
        }
    }
#ifdef BENCH_PRINT
    for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            printf("%d ", wall[i][j]);
        }
        printf("\n");
    }
#endif
}

int main(int argc, char** argv)
{
    init(argc, argv);

    int borderCols = (pyramid_height) * HALO;

    int size = rows * cols;

    int* d_gpuWall;
    int* d_gpuResult[2];
    int* d_outputBuffer;

    cudaError_t err;

    err = cudaMalloc((void**)&d_gpuWall, sizeof(int) * (size - cols));
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMalloc d_gpuWall failed\n");
        exit(1);
    }

    err = cudaMalloc((void**)&d_gpuResult[0], sizeof(int) * cols);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMalloc d_gpuResult[0] failed\n");
        exit(1);
    }

    err = cudaMalloc((void**)&d_gpuResult[1], sizeof(int) * cols);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMalloc d_gpuResult[1] failed\n");
        exit(1);
    }

    err = cudaMalloc((void**)&d_outputBuffer, sizeof(int) * 16384);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMalloc d_outputBuffer failed\n");
        exit(1);
    }

    // Copy data to device
    err = cudaMemcpy(d_gpuWall, data + cols, sizeof(int) * (size - cols), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy d_gpuWall failed\n");
        exit(1);
    }

    err = cudaMemcpy(d_gpuResult[0], data, sizeof(int) * cols, cudaMemcpyHostToDevice);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy d_gpuResult[0] failed\n");
        exit(1);
    }

    int h_outputBuffer[16384];
    memset(h_outputBuffer, 0, sizeof(int) * 16384);

    err = cudaMemcpy(d_outputBuffer, h_outputBuffer, sizeof(int) * 16384, cudaMemcpyHostToDevice);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy d_outputBuffer failed\n");
        exit(1);
    }

    int src = 1, final_ret = 0;

    // Determine block size and grid size
    // We will use 64 threads per block or less if cols < 64
    int BLOCK_SIZE = 64;
    if (cols < BLOCK_SIZE) BLOCK_SIZE = cols;

    int small_block_cols = BLOCK_SIZE - (pyramid_height * HALO * 2);
    if (small_block_cols <= 0) small_block_cols = 1;

    int grid_size = (cols + small_block_cols - 1) / small_block_cols;

    size_t shared_mem_size = 2 * BLOCK_SIZE * sizeof(int);

    for (int t = 0; rows - 1 > t; t += pyramid_height)
    {
        int temp = src;
        src = final_ret;
        final_ret = temp;

        int arg0 = MIN(pyramid_height, rows - t - 1);
        int theHalo = HALO;

        dynproc_kernel<<<grid_size, BLOCK_SIZE, shared_mem_size>>>(
            arg0,
            d_gpuWall,
            d_gpuResult[src],
            d_gpuResult[final_ret],
            cols,
            rows,
            t,
            borderCols,
            theHalo,
            d_outputBuffer);

        err = cudaGetLastError();
        if (err != cudaSuccess) {
            fprintf(stderr, "Kernel launch failed: %s\n", cudaGetErrorString(err));
            exit(1);
        }
        err = cudaDeviceSynchronize();
        if (err != cudaSuccess) {
            fprintf(stderr, "cudaDeviceSynchronize returned error code %d after launching kernel!\n", err);
            exit(1);
        }
    }

    err = cudaMemcpy(result, d_gpuResult[final_ret], sizeof(int) * cols, cudaMemcpyDeviceToHost);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy result failed\n");
        exit(1);
    }

    err = cudaMemcpy(h_outputBuffer, d_outputBuffer, sizeof(int) * 16384, cudaMemcpyDeviceToHost);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy outputBuffer failed\n");
        exit(1);
    }

    h_outputBuffer[16383] = 0;

#ifdef BENCH_PRINT
    for (int i = 0; i < cols; i++)
        printf("%d ", data[i]);
    printf("\n");
    for (int i = 0; i < cols; i++)
        printf("%d ", result[i]);
    printf("\n");
#endif

    cudaFree(d_gpuWall);
    cudaFree(d_gpuResult[0]);
    cudaFree(d_gpuResult[1]);
    cudaFree(d_outputBuffer);

    delete[] data;
    delete[] wall;
    delete[] result;

    return EXIT_SUCCESS;
}
